const raw = $input.first().json.body || {};

const defaults = {
  '语言选择': '英语',
  '模特选择': 'male',
  '字体': 'Sans Serif',
  '品牌': '',
  '产品名称': '',
  '产品介绍': '',
  '反提示词': '',
  '模式': '自动生成',
};

const modelMap = {
  '男性': 'male', '男': 'male', 'male': 'male', 'Male': 'male',
  '女性': 'female', '女': 'female', 'female': 'female', 'Female': 'female',
  '无': 'none', '无模特': 'none', 'none': 'none',
};

const langMap = {
  '英语': '英语', 'english': '英语', 'English': '英语',
  '德语': '德语', 'german': '德语', 'German': '德语',
  '法语': '法语', 'french': '法语', 'French': '法语',
  '俄语': '俄语', 'russian': '俄语', 'Russian': '俄语',
};

const config = {};
for (const [key, def] of Object.entries(defaults)) {
  const val = raw[key];
  config[key] = Array.isArray(val) ? (val[0] || def) : (val || def);
}

config['模特选择'] = modelMap[config['模特选择']] || 'male';
config['语言选择'] = langMap[config['语言选择']] || '英语';
config['模式'] = config['模式'] === '用户布局' ? '用户布局' : '自动生成';

return [{ json: { ...raw, _config: config } }];

const raw = $input.first().json || {};
const json = raw.body || raw;
const productBases = (json['产品图'] || []).filter(Boolean);
const refBases = (json['参考图'] || []).filter(Boolean);
const items = [];
let refIndex = 1;

for (const b64 of productBases) {
  // Strip data:image/xxx;base64, prefix
  const parts = b64.split(',');
  const base64data = parts[1] || parts[0];
  items.push({
    json: { imageType: 'product', refIndex: 0 },
    binary: { image: { data: base64data, mimeType: 'image/jpeg', fileName: 'product.jpg' } }
  });
}
for (const b64 of refBases) {
  const parts = b64.split(',');
  const base64data = parts[1] || parts[0];
  items.push({
    json: { imageType: 'reference', refIndex: refIndex++ },
    binary: { image: { data: base64data, mimeType: 'image/png', fileName: 'ref.png' } }
  });
}
return items.length > 0 ? items : [{ json: { error: 'NO IMAGES' } }];

const productUrls = [];
let referenceUrl = null;

for (const item of $input.all()) {
  const url = item.json.secure_url;
  if (!url) continue;
  if (item.json.imageType === 'reference') {
    referenceUrl = referenceUrl || url;
  } else {
    productUrls.push(url);
  }
}

return [{
  imageUrls: productUrls,
  count: productUrls.length,
  referenceUrl,
  imageContents: productUrls.map(url => ({ type: 'image_url', image_url: url })),
}];

const imageContents = $('提取URL').first().json.imageUrls.map(url => ({
  type: "image_url",
  image_url: url
}));

return [
  {
    imageContents
  }
];

