  messages: [{
    role: "user",
    content: [{
      type: "text",
      text: `你是一名亚马逊电商产品分析助手，该产品${intro}。请仅基于我上传的产品图片和产品介绍进行分析，不得引入图片中未明确展示的信息，不得猜测或虚构功能、材质或使用效果。从图片中识别并描述产品的外观结构、颜色、材质特征、细节设计、可见功能点及潜在使用场景。在此基础上，提炼 3–5 个可以被图片直接验证的产品卖点，卖点需以"用户能获得的实际好处"为导向，表达克制、客观，不使用夸张或极限词。输出内容需符合亚马逊合规与 TOP 100 Listing 风格，语言清晰，可直接用于 Listing 文案或图片策划参考。输出不带换行。`
    }, {
      type: "image_url",
      image_url: { url: $input.first().json.imageContents[0].image_url }
    }]
  }]
};

return [{ json: { body } }];

